def fixed_size(text: str, chunk_size: int = 500, overlap: int = 50) -> list[str]:
    chunks, start = [], 0
    while start < len(text):
        chunks.append(text[start : start + chunk_size])
        start += chunk_size - overlap
    return chunks

import nltk
nltk.download("punkt", quiet=True)

def sentence_based(text: str, max_size: int = 500, min_size: int = 100) -> list[str]:
    sentences = nltk.sent_tokenize(text)
    chunks, current = [], ""
    for s in sentences:
        if len(current) + len(s) <= max_size:
            current += s + " "
        else:
            if len(current) >= min_size:
                chunks.append(current.strip())
            current = s + " "
    if current.strip():
        chunks.append(current.strip())
    return chunks

import re

def markdown_header(text: str) -> list[str]:
    sections = re.split(r"(^#{1,6}\s+.+$)", text, flags=re.MULTILINE)
    chunks, header, content = [], "", ""
    for part in sections:
        part = part.strip()
        if not part:
            continue
        if re.match(r"^#{1,6}\s+", part):
            if content:
                chunks.append(f"{header}\n\n{content}".strip())
            header, content = part, ""
        else:
            content += part + "\n"
    if content:
        chunks.append(f"{header}\n\n{content}".strip())
    return chunks

def rewrite_query(query: str, context: str = "") -> str:
    prompt = f"Rewrite this query to be more specific and searchable:\n\nQuery: {query}"
    if context:
        prompt += f"\n\nContext: {context}"
    resp = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{"role": "user", "content": prompt}],
        temperature=0.3,
    )
    return resp.choices[0].message.content

def retrieve_with_threshold(collection, query_embedding, top_k=10, min_score=0.65):
    results = collection.query(query_embeddings=[query_embedding], n_results=top_k*2,
                               include=["documents", "metadatas", "distances"])
    filtered = [
        (results["documents"][0][i], 1 - results["distances"][0][i],
         results["metadatas"][0][i])
        for i in range(len(results["ids"][0]))
        if 1 - results["distances"][0][i] >= min_score
    ][:top_k]
    return filtered  # Empty list → agent should say "insufficient context"
